     1→"use client";
     2→
     3→import { useCallback, useEffect, useRef, useState } from "react";
     4→import { socket } from "@/lib/socket";
     5→
     6→type MessageRole = "user" | "mira" | "system";
     7→
     8→interface ChatMessage {
     9→  id: string;
    10→  role: MessageRole;
    11→  text: string;
    12→}
    13→
    14→interface ProductItem {
    15→  title: string;
    16→  price: string;
    17→  source: string;
    18→  image_url: string;
    19→  link: string;
    20→  rating?: number;
    21→  rating_count?: number;
    22→}
    23→
    24→interface ProductCard {
    25→  id: string;
    26→  query: string;
    27→  items: ProductItem[];
    28→}
    29→
    30→export default function ChatPage() {
    31→  const [userId, setUserId] = useState("chat-demo-user");
    32→  const [messages, setMessages] = useState<ChatMessage[]>([]);
    33→  const [products, setProducts] = useState<ProductCard[]>([]);
    34→  const [input, setInput] = useState("");
    35→  const [sessionActive, setSessionActive] = useState(false);
    36→  const [connected, setConnected] = useState(false);
    37→  const miraBufferRef = useRef("");
    38→  const messagesEndRef = useRef<HTMLDivElement>(null);
    39→
    40→  const scrollToBottom = useCallback(() => {
    41→    messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    42→  }, []);
    43→
    44→  useEffect(() => {
    45→    scrollToBottom();
    46→  }, [messages, products, scrollToBottom]);
    47→
    48→  // Socket connection & listeners
    49→  useEffect(() => {
    50→    socket.connect();
    51→
    52→    socket.on("connect", () => setConnected(true));
    53→    socket.on("disconnect", () => setConnected(false));
    54→
    55→    socket.on("mira_speech", (data: { text: string; is_chunk: boolean }) => {
    56→      miraBufferRef.current += data.text;
    57→      const currentText = miraBufferRef.current;
    58→
    59→      setMessages((prev) => {
    60→        const last = prev[prev.length - 1];
    61→        if (last && last.role === "mira" && last.id.startsWith("mira-stream-")) {
    62→          return [
    63→            ...prev.slice(0, -1),
    64→            { ...last, text: currentText },
    65→          ];
    66→        }
    67→        return [
    68→          ...prev,
    69→          { id: `mira-stream-${Date.now()}`, role: "mira", text: currentText },
    70→        ];
    71→      });
    72→    });
    73→
    74→    socket.on("tool_result", (data: { type: string; query: string; items: ProductItem[] }) => {
    75→      if (data.type === "clothing_results" && data.items?.length > 0) {
    76→        setProducts((prev) => [
    77→          ...prev,
    78→          { id: `product-${Date.now()}`, query: data.query, items: data.items },
    79→        ]);
    80→      }
    81→    });
    82→
    83→    socket.on("session_ended", (data: { summary: string; stats: { items_shown: number; likes: number; dislikes: number } }) => {
    84→      setSessionActive(false);
    85→      miraBufferRef.current = "";
    86→      setMessages((prev) => [
    87→        ...prev,
    88→        {
    89→          id: `sys-${Date.now()}`,
    90→          role: "system",
    91→          text: `Session ended. ${data.summary || ""} (Items shown: ${data.stats.items_shown}, Likes: ${data.stats.likes}, Dislikes: ${data.stats.dislikes})`,
    92→        },
    93→      ]);
    94→    });
    95→
    96→    socket.on("session_recap", (data: { summary?: string; liked_items?: string[] }) => {
    97→      const parts: string[] = [];
    98→      if (data.summary) parts.push(data.summary);
    99→      if (data.liked_items?.length) parts.push(`Liked items: ${data.liked_items.join(", ")}`);
   100→      if (parts.length > 0) {
   101→        setMessages((prev) => [
   102→          ...prev,
   103→          { id: `recap-${Date.now()}`, role: "system", text: `Recap: ${parts.join(" | ")}` },
   104→        ]);
   105→      }
   106→    });
   107→
   108→    return () => {
   109→      socket.off("connect");
   110→      socket.off("disconnect");
   111→      socket.off("mira_speech");
   112→      socket.off("tool_result");
   113→      socket.off("session_ended");
   114→      socket.off("session_recap");
   115→      socket.disconnect();
   116→    };
   117→  }, []);
   118→
   119→  const joinRoom = useCallback(() => {
   120→    socket.emit("join_room", { user_id: userId });
   121→    setMessages((prev) => [
   122→      ...prev,
   123→      { id: `sys-${Date.now()}`, role: "system", text: `Joined room as ${userId}` },
   124→    ]);
   125→  }, [userId]);
   126→
   127→  const startSession = useCallback(() => {
   128→    miraBufferRef.current = "";
   129→    socket.emit("start_session", { user_id: userId });
   130→    setSessionActive(true);
   131→    setMessages((prev) => [
   132→      ...prev,
   133→      { id: `sys-${Date.now()}`, role: "system", text: "Session started..." },
   134→    ]);
   135→    setProducts([]);
   136→  }, [userId]);
   137→
   138→  const endSession = useCallback(() => {
   139→    socket.emit("end_session", { user_id: userId });
   140→    setMessages((prev) => [
   141→      ...prev,
   142→      { id: `sys-${Date.now()}`, role: "system", text: "Ending session..." },
   143→    ]);
   144→  }, [userId]);
   145→
   146→  const sendMessage = useCallback(() => {
   147→    if (!input.trim()) return;
   148→    const text = input.trim();
   149→    setInput("");
   150→    miraBufferRef.current = "";
   151→    setMessages((prev) => [
   152→      ...prev,
   153→      { id: `user-${Date.now()}`, role: "user", text },
   154→    ]);
   155→    socket.emit("mirror_event", {
   156→      user_id: userId,
   157→      event: { type: "voice", transcript: text },
   158→    });
   159→  }, [input, userId]);
   160→
   161→  const sendGesture = useCallback(
   162→    (gesture: string, label: string) => {
   163→      miraBufferRef.current = "";
   164→      setMessages((prev) => [
   165→        ...prev,
   166→        { id: `user-${Date.now()}`, role: "user", text: `[${label}]` },
   167→      ]);
   168→      socket.emit("mirror_event", {
   169→        user_id: userId,
   170→        event: { type: "gesture", gesture },
   171→      });
   172→    },
   173→    [userId]
   174→  );
   175→
   176→  return (
   177→    <main
   178→      style={{
   179→        maxWidth: 640,
   180→        margin: "0 auto",
   181→        height: "100vh",
   182→        display: "flex",
   183→        flexDirection: "column",
   184→        background: "#0a0a0a",
   185→        color: "#e0e0e0",
   186→        fontFamily: "system-ui, -apple-system, sans-serif",
   187→      }}
   188→    >
   189→      {/* Header */}
   190→      <div
   191→        style={{
   192→          padding: "16px 20px",
   193→          borderBottom: "1px solid #222",
   194→          display: "flex",
   195→          flexDirection: "column",
   196→          gap: 10,
   197→        }}
   198→      >
   199→        <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
   200→          <h1 style={{ margin: 0, fontSize: "1.25rem", color: "#fff" }}>
   201→            Chat with Mira
   202→          </h1>
   203→          <span
   204→            style={{
   205→              fontSize: "0.75rem",
   206→              color: connected ? "#4caf50" : "#f44336",
   207→            }}
   208→          >
   209→            {connected ? "Connected" : "Disconnected"}
   210→          </span>
   211→        </div>
   212→
   213→        {/* User ID + Join */}
   214→        <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
   215→          <input
   216→            type="text"
   217→            value={userId}
   218→            onChange={(e) => setUserId(e.target.value)}
   219→            placeholder="User ID (UUID)"
   220→            style={{
   221→              flex: 1,
   222→              padding: "6px 10px",
   223→              background: "#1a1a1a",
   224→              border: "1px solid #333",
   225→              borderRadius: 6,
   226→              color: "#e0e0e0",
   227→              fontSize: "0.8rem",
   228→            }}
   229→          />
   230→          <button onClick={joinRoom} style={btnStyle("#6b21a8")}>
   231→            Join
   232→          </button>
   233→        </div>
   234→
   235→        {/* Session controls */}
   236→        <div style={{ display: "flex", gap: 8 }}>
   237→          <button
   238→            onClick={startSession}
   239→            disabled={sessionActive}
   240→            style={btnStyle(sessionActive ? "#333" : "#16a34a")}
   241→          >
   242→            Start Session
   243→          </button>
   244→          <button
   245→            onClick={endSession}
   246→            disabled={!sessionActive}
   247→            style={btnStyle(!sessionActive ? "#333" : "#dc2626")}
   248→          >
   249→            End Session
   250→          </button>
   251→        </div>
   252→      </div>
   253→
   254→      {/* Messages */}
   255→      <div
   256→        style={{
   257→          flex: 1,
   258→          overflowY: "auto",
   259→          padding: "16px 20px",
   260→          display: "flex",
   261→          flexDirection: "column",
   262→          gap: 12,
   263→        }}
   264→      >
   265→        {messages.map((msg) => (
   266→          <div
   267→            key={msg.id}
   268→            style={{
   269→              alignSelf:
   270→                msg.role === "user"
   271→                  ? "flex-end"
   272→                  : msg.role === "system"
   273→                  ? "center"
   274→                  : "flex-start",
   275→              maxWidth: msg.role === "system" ? "90%" : "80%",
   276→              padding: "10px 14px",
   277→              borderRadius: 12,
   278→              fontSize: "0.9rem",
   279→              lineHeight: 1.5,
   280→              whiteSpace: "pre-wrap",
   281→              ...(msg.role === "user"
   282→                ? { background: "#6b21a8", color: "#fff" }
   283→                : msg.role === "mira"
   284→                ? { background: "#1a1a2e", color: "#e0e0e0", border: "1px solid #2a2a4e" }
   285→                : { background: "#111", color: "#888", fontSize: "0.8rem", fontStyle: "italic" }),
   286→            }}
   287→          >
   288→            {msg.role === "mira" && (
   289→              <div style={{ fontSize: "0.7rem", color: "#9b59b6", marginBottom: 4, fontWeight: 600 }}>
   290→                Mira
   291→              </div>
   292→            )}
   293→            {msg.text}
   294→          </div>
   295→        ))}
   296→
   297→        {/* Product cards */}
   298→        {products.map((card) => (
   299→          <div key={card.id} style={{ alignSelf: "flex-start", maxWidth: "90%" }}>
   300→            <div style={{ fontSize: "0.75rem", color: "#888", marginBottom: 6 }}>
   301→              Results for &quot;{card.query}&quot;
   302→            </div>
   303→            <div style={{ display: "flex", gap: 10, overflowX: "auto", paddingBottom: 4 }}>
   304→              {card.items.map((item, i) => (
   305→                <a
   306→                  key={i}
   307→                  href={item.link}
   308→                  target="_blank"
   309→                  rel="noopener noreferrer"
   310→                  style={{
   311→                    minWidth: 160,
   312→                    background: "#1a1a2e",
   313→                    border: "1px solid #2a2a4e",
   314→                    borderRadius: 10,
   315→                    padding: 10,
   316→                    textDecoration: "none",
   317→                    color: "#e0e0e0",
   318→                    display: "flex",
   319→                    flexDirection: "column",
   320→                    gap: 6,
   321→                  }}
   322→                >
   323→                  {item.image_url && (
   324→                    <img
   325→                      src={item.image_url}
   326→                      alt={item.title}
   327→                      style={{
   328→                        width: "100%",
   329→                        height: 120,
   330→                        objectFit: "contain",
   331→                        borderRadius: 6,
   332→                        background: "#fff",
   333→                      }}
   334→                    />
   335→                  )}
   336→                  <div style={{ fontSize: "0.8rem", fontWeight: 600 }}>
   337→                    {item.title.length > 50 ? item.title.slice(0, 50) + "..." : item.title}
   338→                  </div>
   339→                  <div style={{ fontSize: "0.85rem", color: "#9b59b6", fontWeight: 700 }}>
   340→                    {item.price}
   341→                  </div>
   342→                  <div style={{ fontSize: "0.7rem", color: "#888" }}>
   343→                    {item.source}
   344→                    {item.rating ? ` | ${item.rating}★` : ""}
   345→                  </div>
   346→                </a>
   347→              ))}
   348→            </div>
   349→          </div>
   350→        ))}
   351→
   352→        <div ref={messagesEndRef} />
   353→      </div>
   354→
   355→      {/* Gesture buttons */}
   356→      <div
   357→        style={{
   358→          display: "flex",
   359→          justifyContent: "center",
   360→          gap: 12,
   361→          padding: "8px 20px",
   362→          borderTop: "1px solid #222",
   363→        }}
   364→      >
   365→        {[
   366→          { gesture: "thumbs_up", label: "Thumbs Up", emoji: "\ud83d\udc4d" },
   367→          { gesture: "thumbs_down", label: "Thumbs Down", emoji: "\ud83d\udc4e" },
   368→          { gesture: "swipe_left", label: "Swipe Left", emoji: "\u2b05\ufe0f" },
   369→          { gesture: "swipe_right", label: "Swipe Right", emoji: "\u27a1\ufe0f" },
   370→        ].map(({ gesture, label, emoji }) => (
   371→          <button
   372→            key={gesture}
   373→            onClick={() => sendGesture(gesture, label)}
   374→            disabled={!sessionActive}
   375→            title={label}
   376→            style={{
   377→              padding: "8px 16px",
   378→              fontSize: "1.3rem",
   379→              background: sessionActive ? "#1a1a2e" : "#111",
   380→              border: "1px solid #2a2a4e",
   381→              borderRadius: 8,
   382→              cursor: sessionActive ? "pointer" : "default",
   383→              opacity: sessionActive ? 1 : 0.4,
   384→            }}
   385→          >
   386→            {emoji}
   387→          </button>
   388→        ))}
   389→      </div>
   390→
   391→      {/* Text input */}
   392→      <div
   393→        style={{
   394→          display: "flex",
   395→          gap: 8,
   396→          padding: "12px 20px 20px",
   397→          borderTop: "1px solid #222",
   398→        }}
   399→      >
   400→        <input
   401→          type="text"
   402→          value={input}
   403→          onChange={(e) => setInput(e.target.value)}
   404→          onKeyDown={(e) => {
   405→            if (e.key === "Enter" && !e.shiftKey) {
   406→              e.preventDefault();
   407→              sendMessage();
   408→            }
   409→          }}
   410→          placeholder={sessionActive ? "Type a message..." : "Start a session first"}
   411→          disabled={!sessionActive}
   412→          style={{
   413→            flex: 1,
   414→            padding: "10px 14px",
   415→            background: "#1a1a1a",
   416→            border: "1px solid #333",
   417→            borderRadius: 8,
   418→            color: "#e0e0e0",
   419→            fontSize: "0.9rem",
   420→            opacity: sessionActive ? 1 : 0.5,
   421→          }}
   422→        />
   423→        <button
   424→          onClick={sendMessage}
   425→          disabled={!sessionActive || !input.trim()}
   426→          style={btnStyle(!sessionActive || !input.trim() ? "#333" : "#6b21a8")}
   427→        >
   428→          Send
   429→        </button>
   430→      </div>
   431→    </main>
   432→  );
   433→}
   434→
   435→function btnStyle(bg: string): React.CSSProperties {
   436→  return {
   437→    padding: "8px 16px",
   438→    background: bg,
